<?php
declare(strict_types=1);
require_once __DIR__ . '/api/bootstrap.php';
$user = mg_require_permission('merchant.gifts.redeem');
$pdo = mg_db();
$merchantUserId = (int)$user['id'];
$summaryStmt = $pdo->prepare("SELECT COUNT(*) total_count, COALESCE(SUM(amount_cents),0) total_amount_cents, COALESCE(SUM(merchant_net_cents),0) total_net_cents, COALESCE(SUM(CASE WHEN settlement_status='pending' THEN merchant_net_cents ELSE 0 END),0) pending_net_cents, COALESCE(SUM(CASE WHEN settlement_status='held' THEN merchant_net_cents ELSE 0 END),0) held_net_cents FROM redemption_settlement_ledger WHERE merchant_user_id=?");
$summaryStmt->execute([$merchantUserId]);
$summary = $summaryStmt->fetch(PDO::FETCH_ASSOC) ?: [];
$recentStmt = $pdo->prepare('SELECT l.*, r.location_name, r.redeemed_at FROM redemption_settlement_ledger l LEFT JOIN scanner_redemption_receipts r ON r.public_id=l.receipt_public_id WHERE l.merchant_user_id=? ORDER BY l.created_at DESC LIMIT 30');
$recentStmt->execute([$merchantUserId]);
$settlements = $recentStmt->fetchAll(PDO::FETCH_ASSOC);
$disputeStmt = $pdo->prepare("SELECT COUNT(*) FROM redemption_disputes WHERE merchant_user_id=? AND status NOT IN ('resolved','dismissed')");
$disputeStmt->execute([$merchantUserId]);
$openDisputes = (int)$disputeStmt->fetchColumn();
$incidentStmt = $pdo->prepare("SELECT COUNT(*) FROM admin_scanner_incidents WHERE merchant_user_id=? AND status IN ('open','reviewing','escalated')");
$incidentStmt->execute([$merchantUserId]);
$openIncidents = (int)$incidentStmt->fetchColumn();
function mg_money_dash(int $cents, string $currency='USD'): string { return strtoupper($currency) . ' ' . number_format($cents/100,2); }
$page_title='Merchant Redemptions | Microgifter'; $page_section='agent'; $header_mode='agent';
require __DIR__ . '/includes/header.php';
?>
<main style="padding:34px 18px;background:#f8fafc;min-height:70vh"><section style="max-width:1180px;margin:0 auto;display:grid;gap:18px"><div><p style="font-size:11px;text-transform:uppercase;letter-spacing:.14em;color:#2563eb;font-weight:900">Merchant operations</p><h1>Redemption Dashboard</h1><p>Track redeemed value, settlement status, disputes, receipts, scanner devices, and incidents.</p></div><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:14px"><article style="background:#fff;border:1px solid #e2e8f0;border-radius:18px;padding:16px"><small>Total redeemed</small><strong style="display:block;font-size:24px"><?= mg_e(mg_money_dash((int)($summary['total_amount_cents'] ?? 0))) ?></strong></article><article style="background:#fff;border:1px solid #e2e8f0;border-radius:18px;padding:16px"><small>Merchant net</small><strong style="display:block;font-size:24px"><?= mg_e(mg_money_dash((int)($summary['total_net_cents'] ?? 0))) ?></strong></article><article style="background:#fff;border:1px solid #e2e8f0;border-radius:18px;padding:16px"><small>Pending settlement</small><strong style="display:block;font-size:24px"><?= mg_e(mg_money_dash((int)($summary['pending_net_cents'] ?? 0))) ?></strong></article><article style="background:#fff;border:1px solid #e2e8f0;border-radius:18px;padding:16px"><small>Held / disputed</small><strong style="display:block;font-size:24px"><?= mg_e((string)$openDisputes) ?></strong></article><article style="background:#fff;border:1px solid #e2e8f0;border-radius:18px;padding:16px"><small>Open incidents</small><strong style="display:block;font-size:24px"><?= mg_e((string)$openIncidents) ?></strong></article></div><section style="background:#fff;border:1px solid #e2e8f0;border-radius:22px;padding:18px;overflow:auto"><h2>Recent redemptions</h2><table style="width:100%;border-collapse:collapse;font-size:13px"><thead><tr><th style="text-align:left;padding:10px">Redeemed</th><th style="text-align:left;padding:10px">Receipt</th><th style="text-align:left;padding:10px">Location</th><th style="text-align:left;padding:10px">Amount</th><th style="text-align:left;padding:10px">Net</th><th style="text-align:left;padding:10px">Status</th></tr></thead><tbody><?php foreach($settlements as $row): ?><tr style="border-top:1px solid #e2e8f0"><td style="padding:10px"><?= mg_e((string)($row['redeemed_at'] ?? $row['created_at'])) ?></td><td style="padding:10px"><a href="/claim-receipt-view.php?id=<?= rawurlencode((string)$row['receipt_public_id']) ?>"><?= mg_e((string)$row['receipt_public_id']) ?></a></td><td style="padding:10px"><?= mg_e((string)($row['location_name'] ?? '')) ?></td><td style="padding:10px"><?= mg_e(mg_money_dash((int)$row['amount_cents'], (string)$row['currency'])) ?></td><td style="padding:10px"><?= mg_e(mg_money_dash((int)$row['merchant_net_cents'], (string)$row['currency'])) ?></td><td style="padding:10px"><?= mg_e((string)$row['settlement_status']) ?></td></tr><?php endforeach; ?><?php if(!$settlements): ?><tr><td style="padding:14px" colspan="6">No redemptions have settled into the ledger yet.</td></tr><?php endif; ?></tbody></table></section><p><a href="/merchant-scanner-settings.php">Scanner settings</a> · <a href="/admin-scanner-incidents.php">Scanner incidents</a></p></section></main>
<?php require __DIR__ . '/includes/footer.php'; ?>
